sql:
SELECT name, tier
FROM municipalities
WHERE interest_payout > (
    SELECT AVG(interest_payout)
    FROM municipalities
);

SELECT m.tier, AVG(m.interest_payout) AS Average_Interest_Payout
FROM municipalities m
GROUP BY m.tier;

external_knowledge:
- 'ocean of data' refers to the database of municipalities;
- 'waves of population' metaphorically refers to the sum of populations;
- 'waters ran deeper' is a metaphor for having a population greater than the average.

sql:
SELECT SUM(stats_can_population_2001) AS total_population
FROM municipalities
WHERE stats_can_population_2001 > (SELECT AVG(stats_can_population_2001) FROM municipalities);

SELECT municipality_id, name
FROM municipalities
WHERE province_id = 10 AND avg_household_income > 50000;

SELECT AVG(interest_payout) AS avg_interest_payout
FROM municipalities
WHERE population_density > (
  SELECT AVG(population_density)
  FROM municipalities
);
